"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ---------------------------------------------------------------------------
// StepperContext — root-level state shared with all descendants
// ---------------------------------------------------------------------------

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 1,
  onValueChange: () => {},
  orientation: "horizontal",
})

function useStepper() {
  return React.useContext(StepperContext)
}

// ---------------------------------------------------------------------------
// StepperItemContext — per-step state shared with trigger / content / etc.
// ---------------------------------------------------------------------------

interface StepperItemContextValue {
  step: number
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 1,
  disabled: false,
})

function useStepperItem() {
  return React.useContext(StepperItemContext)
}

// ---------------------------------------------------------------------------
// Stepper — root container
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  /** Controlled active step (1-based). */
  value?: number
  /** Initial active step when uncontrolled. Defaults to 1. */
  defaultValue?: number
  /** Called whenever the active step changes. */
  onValueChange?: (value: number) => void
  /** Layout direction of the step list. Defaults to "horizontal". */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [uncontrolled, setUncontrolled] = React.useState(defaultValue)
  const active = valueProp ?? uncontrolled

  const handleValueChange = React.useCallback(
    (step: number) => {
      if (valueProp === undefined) {
        setUncontrolled(step)
      }
      onValueChange?.(step)
    },
    [valueProp, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: active, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("cn-stepper group/stepper flex flex-col", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem — wrapper for a single step (trigger + optional content)
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The step number this item represents (1-based). */
  step: number
  /** When true the trigger cannot be activated. */
  disabled?: boolean
}

function StepperItem({
  step,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value } = useStepper()
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, disabled }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        data-disabled={disabled || undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          "group-data-vertical/stepper:flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger — clickable button that activates a step
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={disabled}
      onClick={(e) => {
        if (!disabled) {
          onValueChange(step)
        }
        onClick?.(e)
      }}
      className={cn(
        "cn-stepper-trigger flex cursor-pointer items-center gap-2 rounded-sm text-left transition-colors outline-none",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperTitle — primary label inside a trigger
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription — secondary label inside a trigger
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator — visual divider between step items
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      role="none"
      aria-hidden
      data-slot="stepper-separator"
      className={cn(
        "cn-stepper-separator shrink-0 bg-border",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
        "group-data-vertical/stepper:h-6 group-data-vertical/stepper:w-px group-data-vertical/stepper:self-center",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent — panel shown only when its step is active
// ---------------------------------------------------------------------------

interface StepperContentProps extends React.ComponentProps<"div"> {
  /**
   * The step this content belongs to.
   * Optional when nested directly inside a StepperItem — inferred from
   * StepperItemContext in that case.
   */
  step?: number
}

function StepperContent({
  step: stepProp,
  className,
  ...props
}: StepperContentProps) {
  const { value } = useStepper()
  const { step: stepFromContext } = useStepperItem()
  const step = stepProp ?? stepFromContext
  const isActive = value === step

  return (
    <div
      data-slot="stepper-content"
      data-active={isActive || undefined}
      hidden={!isActive}
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
}

